import React, { useState, useEffect, useMemo } from 'react';
import { Link, NavLink, useLocation, useNavigate } from 'react-router-dom';
import { useData } from '../../contexts/DataContext';
import { ArrowRightOnRectangleIcon } from '@heroicons/react/24/outline';
import AnimatedHamburgerIcon from './AnimatedHamburgerIcon';
import { FacebookIcon, InstagramIcon, YoutubeIcon } from './SocialIcons';
import { NavLink as NavLinkType, SocialLinks } from '../../types';

const Header: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const { data } = useData();
  const location = useLocation();
  const navigate = useNavigate();
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    setIsLoggedIn(sessionStorage.getItem('classroom_access') === 'granted');
    return () => window.removeEventListener('scroll', handleScroll);
  }, [location]);

  const handleLogout = () => {
    sessionStorage.clear();
    setIsLoggedIn(false);
    navigate('/login');
  };

  const navLinks = data?.navLinks || [];

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-700 ${
        isScrolled ? 'bg-pm-dark/80 backdrop-blur-xl py-4 shadow-2xl' : 'bg-transparent py-8'
      }`}
    >
      <div className="max-w-[1800px] mx-auto px-6 sm:px-12 flex justify-between items-center">
        <Link to="/" className="z-50 group">
          <div className="flex items-center gap-3">
             <img src={data?.siteConfig.logo} alt="PMM" className="h-10 w-auto transition-transform duration-500 group-hover:scale-110" />
             <span className="hidden sm:block text-sm font-bold tracking-[0.3em] text-pm-gold uppercase">Perfect Models</span>
          </div>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-12">
          {navLinks.map((link) => (
            <NavLink
              key={link.path}
              to={link.path}
              className={({ isActive }) =>
                `text-[10px] uppercase tracking-[0.3em] font-bold transition-all duration-500 hover:text-pm-gold ${
                  isActive ? 'text-pm-gold' : 'text-white/60'
                }`
              }
            >
              {link.label}
            </NavLink>
          ))}
          <div className="h-4 w-px bg-white/10"></div>
          {isLoggedIn ? (
             <button onClick={handleLogout} className="text-[10px] uppercase tracking-[0.3em] font-bold text-pm-gold flex items-center gap-2">
               <ArrowRightOnRectangleIcon className="w-4 h-4" />
               Sortie
             </button>
          ) : (
             <Link to="/login" className="text-[10px] uppercase tracking-[0.3em] font-bold text-white/60 hover:text-pm-gold">Accès</Link>
          )}
        </nav>

        {/* CTA */}
        <div className="hidden lg:block">
           <Link to="/casting-formulaire" className="btn-premium">
              Rejoindre
           </Link>
        </div>

        {/* Mobile Toggle */}
        <button onClick={() => setIsOpen(!isOpen)} className="lg:hidden z-50 text-pm-gold">
          <AnimatedHamburgerIcon isOpen={isOpen} />
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={`fixed inset-0 bg-pm-dark z-40 flex flex-col items-center justify-center transition-all duration-700 ease-[cubic-bezier(0.19,1,0.22,1)] ${isOpen ? 'translate-y-0' : '-translate-y-full opacity-0'}`}>
          <div className="flex flex-col items-center gap-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="text-3xl font-playfair font-black text-pm-off-white hover:text-pm-gold transition-colors"
              >
                {link.label}
              </Link>
            ))}
            <Link to="/casting-formulaire" onClick={() => setIsOpen(false)} className="btn-premium mt-8">Casting</Link>
          </div>
      </div>
    </header>
  );
};

export default Header;

