    window.addEventListener('scroll', handleScroll);
    setIsLoggedIn(sessionStorage.getItem('classroom_access') === 'granted');
    return () => window.removeEventListener('scroll', handleScroll);
  }, [location]);

  useEffect(() => {
    setIsOpen(false);
  }, [location.pathname]);

  const handleLogout = () => {
    sessionStorage.clear();
    setIsLoggedIn(false);
    navigate('/login');
  };

  const navLinks = data?.navLinks || [];

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-1000 ${
        isScrolled ? 'bg-pm-dark/60 backdrop-blur-2xl py-4 shadow-2xl border-b border-white/5' : 'bg-transparent py-10'
      }`}
    >
      <div className="max-w-[1800px] mx-auto px-6 sm:px-12 flex justify-between items-center">
        <Link to="/" className="z-50 group flex items-center gap-4">
           <img src={data?.siteConfig.logo} alt="PMM" className="h-10 w-auto transition-transform duration-700 group-hover:scale-110 group-hover:rotate-6" />
           <span className="hidden sm:block text-[11px] font-black tracking-[0.5em] text-pm-gold uppercase">Perfect Models</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-12">
          {navLinks.map((link) => (
            <NavLink
              key={link.path}
              to={link.path}
              className={({ isActive }) =>
                `relative text-[10px] uppercase tracking-[0.4em] font-black transition-all duration-500 hover:text-pm-gold ${
                  isActive ? 'text-pm-gold' : 'text-white/40'
                }`
              }
            >
              {link.label}
              {location.pathname === link.path && (
                <motion.div layoutId="nav-underline" className="absolute -bottom-2 left-0 right-0 h-px bg-pm-gold" />
              )}
            </NavLink>
          ))}
          {isLoggedIn ? (
             <button onClick={handleLogout} className="text-[10px] uppercase tracking-[0.4em] font-black text-pm-gold flex items-center gap-2 hover:text-white transition-colors">
               <ArrowRightOnRectangleIcon className="w-4 h-4" />
               Log out
             </button>
          ) : (
             <Link to="/login" className="text-[10px] uppercase tracking-[0.4em] font-black text-white/40 hover:text-pm-gold">Client Access</Link>
          )}
        </nav>

        {/* CTA */}
        <div className="hidden lg:block">
           <Link to="/casting-formulaire" className="btn-premium !py-3 !px-8 text-[9px]">
              Apply Now
           </Link>
        </div>

        {/* Mobile Toggle */}
        <button onClick={() => setIsOpen(!isOpen)} className="lg:hidden z-50 text-pm-gold focus:outline-none">
          <AnimatedHamburgerIcon isOpen={isOpen} />
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isOpen && (
          <motion.div 
            initial={{ y: "-100%" }}
            animate={{ y: 0 }}
            exit={{ y: "-100%" }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className="fixed inset-0 bg-pm-dark z-40 flex flex-col items-center justify-center p-12"
          >
              <div className="flex flex-col items-center gap-10">
                {navLinks.map((link, idx) => (
                  <motion.div
                    key={link.path}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 + idx * 0.1 }}
                  >
                    <Link
                      to={link.path}
                      onClick={() => setIsOpen(false)}
                      className="text-4xl sm:text-6xl font-playfair font-black text-pm-off-white hover:text-pm-gold transition-colors italic"
                    >
                      {link.label}
                    </Link>
                  </motion.div>
                ))}
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 1 }}
                  className="flex flex-col gap-6 items-center mt-12"
                >
                  <Link to="/casting-formulaire" onClick={() => setIsOpen(false)} className="btn-premium !px-16 !py-6 text-sm">Join the Agency</Link>
                  {isLoggedIn && <button onClick={handleLogout} className="text-xs font-black text-pm-gold uppercase tracking-[0.4em]">Sign Out</button>}
                </motion.div>
              </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
};

